# --- Rate limiting (simple per-IP, per-username) ---
sub check_rate_limit {
    my ($username) = @_;
    my $ip = $ENV{'REMOTE_ADDR'} // 'unknown';
    my $dbh = get_dbh();

    # Check failed attempts in last 15 minutes
    my $sth = $dbh->prepare(q{
        SELECT COUNT(*) FROM login_attempts
        WHERE (username = ? OR ip_address = ?)
          AND success = FALSE
          AND attempted_at > NOW() - INTERVAL '15 minutes'
    });
    $sth->execute($username, $ip);
    my ($count) = $sth->fetchrow_array;
    $sth->finish;
    $dbh->disconnect;

    # Max 5 failed attempts per 15 minutes
    return $count < 5;
}

sub record_login_attempt {
    my ($username, $success) = @_;
    my $dbh = get_dbh();
    my $sth = $dbh->prepare(q{
        INSERT INTO login_attempts (username, ip_address, success, attempted_at)
        VALUES (?, ?, ?, NOW())
    });
    $sth->execute($username, $ENV{'REMOTE_ADDR'} // 'unknown', $success ? 1 : 0);
    $sth->finish;
    $dbh->disconnect;
}

# --- CSRF token management ---
sub generate_csrf_token {
    return encode_base64(urandom(32), '');
}

sub validate_csrf_token {
    my ($session, $submitted_token) = @_;
    my $stored_token = $session->param('csrf_token');
    return 0 unless defined $stored_token && defined $submitted_token;
    return _constant_time_eq($stored_token, $submitted_token);
}

# --- Authenticate user ---
sub authenticate {
    my ($username, $password) = @_;

    return (0, 'Invalid input') unless defined $username && defined $password;
    return (0, 'Invalid input') if length($username) > 255 || length($password) > 1024;
    return (0, 'Invalid input') if $username !~ /\A[a-zA-Z0-9_.\@\-]+\z/;

    unless (check_rate_limit($username)) {
        _log_security_event($username, 'RATE_LIMITED');
        return (0, 'Too many failed attempts. Please try again later.');
    }

    my $dbh = get_dbh();
    my $sth = $dbh->prepare(q{
        SELECT username, password_hash_argon2, password_hash_md5, hash_algorithm, account_locked
        FROM users
        WHERE username = ?
    });
    $sth->execute($username);
    my $user = $sth->fetchrow_hashref;
    $sth->finish;
    $dbh->disconnect;

    # Always perform work to prevent user enumeration timing attacks
    unless ($user) {
        # Perform a dummy hash to keep timing consistent
        hash_password_argon2("dummy_password_for_timing");
        record_login_attempt($username, 0);
        return (0, 'Invalid username or password.');
    }

    if ($user->{account_locked}) {
        _log_security_event($username, 'LOGIN_ATTEMPT_LOCKED_ACCOUNT');
        record_login_attempt($username, 0);
        return (0, 'Account is locked. Please contact support.');
    }

    my $authenticated = 0;

    # Try modern Argon2id hash first
    if ($user->{hash_algorithm} eq 'argon2id' && defined $user->{password_hash_argon2}) {
        eval {
            $authenticated = verify_password_argon2($password, $user->{password_hash_argon2});
        };
        if ($@) {
            warn "Argon2 verification error for user $username: $@";
            $authenticated = 0;
        }
    }
    # Fall back to legacy MD5 verification with automatic migration
    elsif ($user->{hash_algorithm} eq 'md5' && defined $user->{password_hash_md5}) {
        $authenticated = verify_and_migrate_legacy(
            $username, $password, $user->{password_hash_md5}
