        record_login_attempt($username, 1);
        _log_security_event($username, 'LOGIN_SUCCESS');

        # Check if Argon2 parameters need rehashing (parameter upgrade)
        if ($user->{hash_algorithm} eq 'argon2id') {
            _maybe_rehash($username, $password, $user->{password_hash_argon2});
        }

        return (1, 'Authenticated successfully.');
    } else {
        record_login_attempt($username, 0);
        _log_security_event($username, 'LOGIN_FAILED');
        return (0, 'Invalid username or password.');
    }
