# --- Rehash if parameters have been upgraded ---
sub _maybe_rehash {
    my ($username, $password, $current_hash) = @_;
    # Argon2 encoded string contains parameters; check if they match current config
    # If our security parameters have been increased, rehash
    if ($current_hash =~ /m=(\d+),t=(\d+),p=(\d+)/) {
        my ($m, $t, $p) = ($1, $2, $3);
        my $target_m = 65536; # 64M in KiB
        if ($t < $ARGON2_T_COST || $m < $target_m || $p < $ARGON2_PARALLEL) {
            my $new_hash = hash_password_argon2($password);
            _update_password_hash($username, $new_hash);
            _log_security_event($username, 'PASSWORD_REHASHED_PARAMS_UPGRADE');
        }
    }
}

# --- Store new password ---
sub store_password {
    my ($username, $password) = @_;

    # Password strength validation
    return (0, 'Password must be at least 12 characters.') if length($password) < 12;
    return (0, 'Password too long.') if length($password) > 1024;

    my $argon2_hash = hash_password_argon2($password);

    my $dbh = get_dbh();
    my $sth = $dbh->prepare(q{
        UPDATE users
        SET password_hash_argon2 = ?,
            password_hash_md5    = NULL,
            hash_algorithm       = 'argon2id',
            password_updated_at  = NOW()
        WHERE username = ?
