    my ($auth_ok, $auth_msg) = authenticate($username, $old_password);
    unless ($auth_ok) {
        print $cgi->header(%security_headers, -cookie => $session_cookie);
        print_change_password_page('Current password is incorrect.', $session->param('csrf_token'));
        exit;
