    my $csrf = generate_csrf_token_for_session($session);
    print $cgi->header(%security_headers, -cookie => $session_cookie);
    print_login_page('', $csrf);
}

$session->flush;

# --- Helper: ensure session has CSRF token ---
sub generate_csrf_token_for_session {
    my ($sess) = @_;
    my $token = $sess->param('csrf_token');
    unless ($token) {
        $token = generate_csrf_token();
        $sess->param('csrf_token', $token);
    }
    return $token;
}

